let dados = {};
const input = $json.query;

if (typeof input === 'string') {
    // Função auxiliar para extrair o valor após um rótulo específico
    // Ela procura pelo nome do campo, ignora espaços e pega tudo até o fim da linha ou próximo campo
    const extrair = (campo) => {
        const regex = new RegExp(`${campo}:\\s*([^\\n]+)`, 'i');
        const match = input.match(regex);
        return match ? match[1].trim() : null;
    };

    dados = {
        url_arquivo: extrair('url_arquivo'),
        tipo: extrair('tipo'),
        accountId: extrair('accountId'),
        bankName: extrair('bankName'),
        accountName: extrair('accountName'),
        userId: extrair('userId'),
        ownerId: extrair('ownerId')
    };

    // Caso o Regex falhe e não encontre nada, cai no catch de segurança
    if (!dados.url_arquivo && !dados.tipo) {
        throw new Error("Não foi possível extrair os dados do texto da IA.");
    }
} 
else if (typeof input === 'object') {
    dados = input;
} 
else {
    dados = $json;
}

return [{ json: dados }];

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64String = binaryData.toString('base64');

const mimeType = $input.item.binary.data.mimeType || 'application/pdf';
const fileExtension = mimeType.split('/')[1] || 'pdf';

// Pega o nome original que veio com sujeira
let fileName = $input.item.binary.data.fileName || `documento_whatsapp.${fileExtension}`;

// LIMPEZA: Remove o "-filename*=" e tudo que vier depois
if (fileName.includes('-filename')) {
    fileName = fileName.split('-filename')[0];
}

// LIMPEZA EXTRA (Opcional): Se o arquivo ficar com ".pdf.pdf", corrige para um só
if (fileName.endsWith('.pdf.pdf')) {
    fileName = fileName.replace('.pdf.pdf', '.pdf');
}

return [{
  json: {
    base64File: base64String,
    mimeType: mimeType,
    fileName: fileName
  }
}];
